import pika
import json
import sys
from typing import Dict, Any

def create_connection():
    """Create secure connection to RabbitMQ with default credentials"""
    try:
        # Use default RabbitMQ credentials
        credentials = pika.PlainCredentials('guest', 'guest')
        parameters = pika.ConnectionParameters(
            host='localhost',
            port=5672,
            credentials=credentials,
            heartbeat=30,
            blocked_connection_timeout=30
        )
        connection = pika.BlockingConnection(parameters)
        return connection
    except Exception as e:
        print(f"Failed to connect to RabbitMQ: {e}")
        sys.exit(1)

def publish_task(task_data: Dict[str, Any], queue_name: str = 'task_queue'):
    """Publish a task message to RabbitMQ queue"""
    connection = create_connection()
    channel = connection.channel()
    
    # Declare queue
    channel.queue_declare(queue=queue_name, durable=True)
    
    # Publish message
    message = json.dumps(task_data)
    channel.basic_publish(
        exchange='',
        routing_key=queue_name,
        body=message,
        properties=pika.BasicProperties(
            delivery_mode=2,  # Make message persistent
        )
    )
    
    print(f"Task published: {task_data}")
    connection.close()

def consume_tasks(queue_name: str = 'task_queue', callback_func=None):
    """Consume tasks from RabbitMQ queue"""
    connection = create_connection()
    channel = connection.channel()
    
    # Declare queue
    channel.queue_declare(queue=queue_name, durable=True)
    
    # Set up callback function
    if callback_func is None:
        def default_callback(ch, method, properties, body):
            task = json.loads(body)
            print(f"Processing task: {task}")
            # Simulate task processing
            try:
                # Your task processing logic here
                result = f"Processed: {task}"
                print(result)
                ch.basic_ack(delivery_tag=method.delivery_tag)
            except Exception as e:
                print(f"Error processing task: {e}")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
        
        callback_func = default_callback
    
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue=queue_name, on_message_callback=callback_func)
    
    print("Waiting for tasks. To exit press CTRL+C")
    try:
        channel.start_consuming()
    except KeyboardInterrupt:
        print("Stopping consumer...")
        channel.stop_consuming()
        connection.close()

